<?php
 class Application { private Router $router; public function __construct() { $this->router = new Router(); $this->initDatabase(); } public function run(): void { $route = $this->router->parseRoute(); $controllerName = ucfirst($route['controller']) . 'Controller'; $actionName = 'action_' . $route['action']; if (!class_exists($controllerName)) { $this->show404("Контролер '{$route['controller']}' не знайдено."); return; } $controller = new $controllerName(); if (!method_exists($controller, $actionName)) { $this->show404("Дію '{$route['action']}' не знайдено в контролері '{$route['controller']}'."); return; } $controller->$actionName(); } private function initDatabase(): void { $dbPath = ROOT_DIR . '/database/app.db'; $dbDir = dirname($dbPath); if (!is_dir($dbDir)) { mkdir($dbDir, 0755, true); } $schemaPath = ROOT_DIR . '/database/schema.sql'; if (file_exists($schemaPath)) { $db = Database::getInstance(); try { $db->exec(file_get_contents($schemaPath)); } catch (PDOException $e) { /* ALTER TABLE may already exist; continue */ } $this->ensureLab6Schema($db); } } private function ensureLab6Schema(PDO $db): void { $commands = [ "ALTER TABLE users ADD COLUMN age INTEGER DEFAULT NULL", "CREATE TABLE IF NOT EXISTS products (id INTEGER PRIMARY KEY AUTOINCREMENT, name VARCHAR(100) NOT NULL, category VARCHAR(50) NOT NULL, price DECIMAL(10,2) NOT NULL DEFAULT 0, description TEXT DEFAULT '', image VARCHAR(255) DEFAULT '', created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP)", "CREATE TABLE IF NOT EXISTS invoices (id INTEGER PRIMARY KEY AUTOINCREMENT, user_id INTEGER NOT NULL, product_id INTEGER NOT NULL, invoice_date DATE NOT NULL, quantity INTEGER NOT NULL, total_amount DECIMAL(10,2) NOT NULL, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE, FOREIGN KEY (product_id) REFERENCES products(id) ON DELETE CASCADE)", "INSERT OR REPLACE INTO products (id, name, category, price, description, image) VALUES (1, 'Футболка з логотипом Space Engine', 'Apparel', 699.00, 'Чорна футболка з логотипом міні-гри. Фото можна замінити через редагування товару.', ''), (2, 'Кепка з логотипом Space Engine', 'Accessories', 449.00, 'Кепка для фанатів Space Engine з місцем під фото логотипу.', ''), (3, 'Ракета з емблемою Space Engine', 'Collectible', 1299.00, 'Колекційна модель ракети з емблемою міні-гри для космічної полиці.', ''), (4, 'Стікер-пак космічного пілота', 'Desk Gear', 149.00, 'Набір наліпок з кораблями, планетами та написом Space Engine.', '')", "INSERT OR IGNORE INTO users (login, password, email, first_name, last_name, phone, city, gender, about, role, age) VALUES ('admin@admin.com', '$2y$12$TgH78YFWxunnlRjKuNYG2OMgZDRDUxfu5p5qzQhRL66JOVpg3gfEe', 'admin@admin.com', 'Administrator', '', '', 'Orbital Station', 'male', 'Lab 6 administrator.', 'admin', NULL)" ]; foreach ($commands as $sql) { try { $db->exec($sql); } catch (PDOException $e) { } } } private function show404(string $message): void { http_response_code(404); $view = new PageView(); $view->setTitle('404 — Сторінку не знайдено'); $view->render('layout/404', ['message' => $message]); } } 